        public override string ToString()
        {
            var sb = new StringBuilder(100);
            var m = new SpreadBookQuoteMessage();
            m.WrapForDecode(_buffer, _offset, _actingBlockLength, _actingVersion);
            m.BuildString(sb);
            return sb.ToString();
        }

        internal void BuildString(StringBuilder builder)
        {
            if (_buffer == null)
            {
                throw new ArgumentNullException("_buffer");
            }

            int originalLimit = this.Limit;
            this.Limit = _offset + _actingBlockLength;
            builder.Append("[SpreadBookQuoteMessage](sbeTemplateId=");
            builder.Append(SpreadBookQuoteMessage.TemplateId);
            builder.Append("|sbeSchemaId=");
            builder.Append(SpreadBookQuoteMessage.SchemaId);
            builder.Append("|sbeSchemaVersion=");
            if (_parentMessage._actingVersion != SpreadBookQuoteMessage.SchemaVersion)
            {
                builder.Append(_parentMessage._actingVersion);
                builder.Append('/');
            }
            builder.Append(SpreadBookQuoteMessage.SchemaVersion);
            builder.Append("|sbeBlockLength=");
            if (_actingBlockLength != SpreadBookQuoteMessage.BlockLength)
            {
                builder.Append(_actingBlockLength);
                builder.Append('/');
            }
            builder.Append(SpreadBookQuoteMessage.BlockLength);
            builder.Append("):");

            builder.Append("FromCache=");
            builder.Append(this.FromCache);
            builder.Append('|');
            builder.Append("IsBidPrice1Valid=");
            builder.Append(this.IsBidPrice1Valid);
            builder.Append('|');
            builder.Append("IsAskPrice1Valid=");
            builder.Append(this.IsAskPrice1Valid);
            builder.Append('|');
            builder.Append("IsBidPrice2Valid=");
            builder.Append(this.IsBidPrice2Valid);
            builder.Append('|');
            builder.Append("IsAskPrice2Valid=");
            builder.Append(this.IsAskPrice2Valid);
            builder.Append('|');
            builder.Append("BidExch1=");
            builder.Append(this.BidExch1);
            builder.Append('|');
            builder.Append("AskExch1=");
            builder.Append(this.AskExch1);
            builder.Append('|');
            builder.Append("UpdateType=");
            builder.Append(this.UpdateType);
            builder.Append('|');
            builder.Append("BidMask1=");
            builder.Append(this.BidMask1);
            builder.Append('|');
            builder.Append("AskMask1=");
            builder.Append(this.AskMask1);
            builder.Append('|');
            builder.Append("BidSize1=");
            builder.Append(this.BidSize1);
            builder.Append('|');
            builder.Append("AskSize1=");
            builder.Append(this.AskSize1);
            builder.Append('|');
            builder.Append("BidSize2=");
            builder.Append(this.BidSize2);
            builder.Append('|');
